#include <stdio.h>
#include <stdlib.h>
#define MAXN 250005
typedef struct { int* data; int size; } Set;
Set* sets[MAXN];
void initSets(int N) { for (int i = 0; i < N; i++) { sets[i] = (Set*)malloc(sizeof(Set)); sets[i]->data = NULL; sets[i]->size = 0; } }
void add(int N, int l, int r, int x) { for (int i = l - 1; i < r; i++) { int* newData = (int*)realloc(sets[i]->data, (sets[i]->size + 1) * sizeof(int)); if (newData == NULL) { printf("Memory error\n"); return; } sets[i]->data = newData; int j; for (j = 0; j < sets[i]->size; j++) if (sets[i]->data[j] == x) break; if (j == sets[i]->size) { sets[i]->data[sets[i]->size] = x; sets[i]->size++; } } }
int query(int q) { return sets[q - 1]->size; }
int main() { int N, M; scanf("%d %d", &N, &M); initSets(N); for (int i = 0; i < M; i++) { int type; scanf("%d", &type); if (type == 0) { int l, r, x; scanf("%d %d %d", &l, &r, &x); add(N, l, r, x); } else { int q; scanf("%d", &q); printf("%d\n", query(q)); } } return 0; }

