#include <iostream>
#include <vector>
using namespace std;
typedef vector<int> Set;
Set sets[250005];
void add(int N, int l, int r, int x) { for (int i = l - 1; i < r; i++) { bool found = false; for (int j = 0; j < sets[i].size(); j++) if (sets[i][j] == x) { found = true; break; } if (!found) sets[i].push_back(x); } }
int query(int q) { return sets[q - 1].size(); }
int main() { int N, M; cin >> N >> M; for (int i = 0; i < M; i++) { int type; cin >> type; if (type == 0) { int l, r, x; cin >> l >> r >> x; add(N, l, r, x); } else { int q; cin >> q; cout << query(q) << endl; } } return 0; }

