const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const nextLine = () => lines[idx++];
const nextInts = () => nextLine().split(' ').map(x => parseInt(x));
const N = nextInts()[0];
const M = nextInts()[1];
const sets = Array(N).fill().map(() => new Set());
function add(l, r, x) {
    for (let i = l - 1; i < r; i++) {
        sets[i].add(x);
    }
}
function query(q) {
    return sets[q - 1].size;
}
for (let i = 0; i < M; i++) {
    const [type, ...args] = nextInts();
    if (type === 0) {
        const [l, r, x] = args;
        add(l, r, x);
    } else {
        const [q] = args;
        console.log(query(q));
    }
}

